import{_ as n,o as a,c as l,af as o}from"./chunks/framework.SW4JcFcZ.js";const A=JSON.parse('{"title":"Android媒体库更新问题","description":"","frontmatter":{"title":"Android媒体库更新问题","date":"2019-09-21T00:00:00.000Z","excerpt":"","tags":["Android","MediaProvider"],"categories":["Android"]},"headers":[],"relativePath":"blog/posts/Android媒体库更新问题.md","filePath":"blog/posts/Android媒体库更新问题.md","lastUpdated":null}'),p={name:"blog/posts/Android媒体库更新问题.md"};function e(t,s,c,r,i,d){return a(),l("div",null,[...s[0]||(s[0]=[o(`<blockquote><p>这篇博文是从本人过去的 github pages 博客迁移过来，时间上会比较古老。</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>Android 媒体库(MediaProvider)实际上是个 Provider。</p><p><strong>Android 4.4</strong> 以后，当<strong>系统启动完成</strong>、<strong>SD 卡插拔</strong>或者<strong>接收到 <code>Intent.ACTION_MEDIA_SCANNER_SCAN_FILE</code> 广播</strong>时，系统会扫描文件系统中的数据，将新增和删除的文件信息更新到这个 MediaProvider 中。其他应用如果要使用，直接读取这个 MediaProvider 就可以直接取得系统中媒体文件的信息。</p><h2 id="背景" tabindex="-1">背景 <a class="header-anchor" href="#背景" aria-label="Permalink to &quot;背景&quot;">​</a></h2><p>笔者遇到的问题是开发的拍照应用在拍照之后，MediaProvider 没有更新新增的照片文件，图库中也看不到新增的照片。</p><h2 id="调查过程" tabindex="-1">调查过程 <a class="header-anchor" href="#调查过程" aria-label="Permalink to &quot;调查过程&quot;">​</a></h2><p>从触发更新 MediaProvider 的条件来看，拍照之后应该发送广播<code>Intent.ACTION_MEDIA_SCANNER_SCAN_FILE</code>通知系统去更新 MediaProvider，而开发的相机应用没有进行这个动作。</p><p>笔者写了一个类用来发送<code>Intent.ACTION_MEDIA_SCANNER_SCAN_FILE</code>广播：</p><div class="language-java"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki github-light vp-code" tabindex="0"><code><span class="line"><span style="color:#D73A49;">public</span><span style="color:#D73A49;"> class</span><span style="color:#6F42C1;"> MediaUtils</span><span style="color:#24292E;"> {</span></span>
<span class="line"><span style="color:#D73A49;">    private</span><span style="color:#D73A49;"> static</span><span style="color:#D73A49;"> final</span><span style="color:#24292E;"> String TAG </span><span style="color:#D73A49;">=</span><span style="color:#032F62;"> &quot;MediaUtils&quot;</span><span style="color:#24292E;">;</span></span>
<span class="line"><span style="color:#D73A49;">    private</span><span style="color:#D73A49;"> static</span><span style="color:#24292E;"> MediaUtils sInstance;</span></span>
<span class="line"><span style="color:#D73A49;">    private</span><span style="color:#24292E;"> Context mContext;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D73A49;">    public</span><span style="color:#D73A49;"> static</span><span style="color:#D73A49;"> synchronized</span><span style="color:#24292E;"> MediaUtils </span><span style="color:#6F42C1;">getInstance</span><span style="color:#24292E;">() {</span></span>
<span class="line"><span style="color:#24292E;">        Log.</span><span style="color:#6F42C1;">d</span><span style="color:#24292E;">(TAG, </span><span style="color:#032F62;">&quot;getInstance()&quot;</span><span style="color:#24292E;">);</span></span>
<span class="line"><span style="color:#D73A49;">        if</span><span style="color:#24292E;"> (sInstance </span><span style="color:#D73A49;">==</span><span style="color:#005CC5;"> null</span><span style="color:#24292E;">) {</span></span>
<span class="line"><span style="color:#24292E;">            sInstance </span><span style="color:#D73A49;">=</span><span style="color:#D73A49;"> new</span><span style="color:#6F42C1;"> MediaUtils</span><span style="color:#24292E;">();</span></span>
<span class="line"><span style="color:#24292E;">        }</span></span>
<span class="line"><span style="color:#D73A49;">        return</span><span style="color:#24292E;"> sInstance;</span></span>
<span class="line"><span style="color:#24292E;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#D73A49;">    private</span><span style="color:#6F42C1;"> MediaUtils</span><span style="color:#24292E;">() {}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">    /**</span></span>
<span class="line"><span style="color:#6A737D;">     * set Context: send BroadCast need a Context.</span></span>
<span class="line"><span style="color:#6A737D;">     * </span><span style="color:#D73A49;">@param</span><span style="color:#E36209;"> context</span><span style="color:#6A737D;"> context</span></span>
<span class="line"><span style="color:#6A737D;">     */</span></span>
<span class="line"><span style="color:#D73A49;">    public</span><span style="color:#D73A49;"> void</span><span style="color:#6F42C1;"> setContext</span><span style="color:#24292E;">(@</span><span style="color:#D73A49;">NonNull</span><span style="color:#24292E;"> Context </span><span style="color:#E36209;">context</span><span style="color:#24292E;">) {</span></span>
<span class="line"><span style="color:#24292E;">        Log.</span><span style="color:#6F42C1;">d</span><span style="color:#24292E;">(TAG, </span><span style="color:#032F62;">&quot;setContext()&quot;</span><span style="color:#24292E;">);</span></span>
<span class="line"><span style="color:#24292E;">        mContext </span><span style="color:#D73A49;">=</span><span style="color:#24292E;"> context;</span></span>
<span class="line"><span style="color:#24292E;">    }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6A737D;">    /**</span></span>
<span class="line"><span style="color:#6A737D;">     * update Media.</span></span>
<span class="line"><span style="color:#6A737D;">     * </span><span style="color:#D73A49;">@param</span><span style="color:#E36209;"> filePath</span><span style="color:#6A737D;"> path of updated file</span></span>
<span class="line"><span style="color:#6A737D;">     */</span></span>
<span class="line"><span style="color:#D73A49;">    public</span><span style="color:#D73A49;"> void</span><span style="color:#6F42C1;"> updateMedia</span><span style="color:#24292E;">(@</span><span style="color:#D73A49;">NonNull</span><span style="color:#24292E;"> String </span><span style="color:#E36209;">filePath</span><span style="color:#24292E;">) {</span></span>
<span class="line"><span style="color:#24292E;">        Log.</span><span style="color:#6F42C1;">d</span><span style="color:#24292E;">(TAG, </span><span style="color:#032F62;">&quot;updateMedia() filePath:&quot;</span><span style="color:#D73A49;"> +</span><span style="color:#24292E;"> filePath);</span></span>
<span class="line"><span style="color:#24292E;">        Intent intent </span><span style="color:#D73A49;">=</span><span style="color:#D73A49;"> new</span><span style="color:#6F42C1;"> Intent</span><span style="color:#24292E;">(Intent.ACTION_MEDIA_SCANNER_SCAN_FILE);</span></span>
<span class="line"><span style="color:#24292E;">        intent.</span><span style="color:#6F42C1;">setData</span><span style="color:#24292E;">(Uri.</span><span style="color:#6F42C1;">fromFile</span><span style="color:#24292E;">(</span><span style="color:#D73A49;">new</span><span style="color:#6F42C1;"> File</span><span style="color:#24292E;">(filePath)));</span></span>
<span class="line"><span style="color:#24292E;">        mContext.</span><span style="color:#6F42C1;">sendBroadcast</span><span style="color:#24292E;">(intent);</span></span>
<span class="line"><span style="color:#24292E;">    }</span></span>
<span class="line"><span style="color:#24292E;">}</span></span></code></pre></div><p>在拍照<code>Activity</code>取得<code>MediaUtils</code>的实例并调用<code>setContext</code>方法传入<code>Activity</code>本身。</p><p>在拍照之后取得 MediaUtils 的实例并调用<code>updateMedia</code>方法将新增照片的路径传入，相册里就可以显示新增的照片了。</p><h2 id="结论" tabindex="-1">结论 <a class="header-anchor" href="#结论" aria-label="Permalink to &quot;结论&quot;">​</a></h2><p>如果想要应用产生的图片或者视频被其他应用找到并使用，必须要发送<code>Intent.ACTION_MEDIA_SCANNER_SCAN_FILE</code>广播。</p>`,14)])])}const E=n(p,[["render",e]]);export{A as __pageData,E as default};
